from pathlib import Path

AC_UID = "cross_session_isolation_06"
AC_TYPE = "hook"

AGENT_MD = Path(__file__).resolve().parents[3] / "agents" / "changelog-analyst.md"


def test_AC_06():
    """
    GIVEN: agents/changelog-analyst.md is read
    WHEN:  cross-session isolation logic is inspected
    THEN:  (a) foreign_session_candidate exclusion; (b) dev-report as primary whitelist;
           (c) baseline_head_sha absent → whitelist + foreign-session exclusion still apply;
           (d) no dev-report → fallback with WARNING; (e) BULK=true unchanged.
    """
    text = AGENT_MD.read_text()
    for token in ("foreign_session_candidate", "excluding", "not attributable", "whitelist"):
        assert token in text, f"required token {token!r} missing"
    # Baseline-absent behavior: provenance skipped but whitelist enforced
    assert "baseline_head_sha" in text
    assert "provenance filter skipped" in text or "provenance check is skipped" in text or \
           "provenance sanity check is skipped" in text, "baseline-absent provenance-skip clause missing"
    # No-dev-report fallback with WARNING
    assert "no dev-report" in text.lower() or "no dev report" in text.lower()
    assert "stage-all" in text or "stage everything" in text.lower()
    # BULK=true unchanged
    assert "BULK=true" in text
